import React, { useEffect, useState, useRef } from "react";
import {
  Trash2,
  Pencil,
  Plus,
  ChevronDown,
  Search,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const sortOptions = [
  { label: "Sort by Position", value: "order" },
  { label: "Sort by Name", value: "name" },
  { label: "Sort by Status", value: "status" },
];

const statusOptions = [
  { label: "Active", value: true },
  { label: "Inactive", value: false },
];

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [view, setView] = useState("home");
  const [sort, setSort] = useState("order");
  const [search, setSearch] = useState("");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [statusDropdown, setStatusDropdown] = useState(false);

  const dropdownRef = useRef(null);
  const statusRef = useRef(null);

  const [name, setName] = useState("");
  const [isActive, setIsActive] = useState(true);

  const fetchLinks = async () => {
    const res = await fetch(API);
    const data = await res.json();
    setLinks(data.filter((l) => !l.parent));
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  useEffect(() => {
    const handler = (e) => {
      if (!dropdownRef.current?.contains(e.target))
        setDropdownOpen(false);
      if (!statusRef.current?.contains(e.target))
        setStatusDropdown(false);
    };
    document.addEventListener("mousedown", handler);
    return () =>
      document.removeEventListener("mousedown", handler);
  }, []);

  const processedLinks = [...links]
    .filter((l) =>
      l.name.toLowerCase().includes(search.toLowerCase())
    )
    .sort((a, b) => {
      if (sort === "name") return a.name.localeCompare(b.name);
      if (sort === "status") return b.isActive - a.isActive;
      return 0;
    });

  const handleSubmit = async (e) => {
    e.preventDefault();

    await fetch(API, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, isActive, parent: null }),
    });

    setName("");
    setIsActive(true);
    setView("home");
    fetchLinks();
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        {/* HEADER */}
        <div className={design.header}>
          <h1 className={design.title}>
            Parent Navigation Links
          </h1>
          <p className={design.subtitle}>
            Manage only main menu navigation.
          </p>

          <div className={design.pathWrapper}>
            {view === "home" && (
              <span className={design.pathActive}>
                linkhome
              </span>
            )}

            {view === "add" && (
              <>
                <span
                  onClick={() => setView("home")}
                  className={design.path}
                >
                  linkhome
                </span>
                <span className={design.pathDivider}>/</span>
                <span className={design.pathActive}>
                  add-link
                </span>
              </>
            )}
          </div>
        </div>

        <AnimatePresence mode="wait">
          {view === "home" && (
            <motion.div
              key="home"
              initial={{ opacity: 0, x: -30 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 30 }}
              transition={{ duration: 0.3 }}
              className="space-y-6"
            >
              {/* NAVBAR */}
              <div className={design.navbar}>
                <div className={design.searchWrapper}>
                  <Search size={16} />
                  <input
                    type="text"
                    placeholder="Search link..."
                    value={search}
                    onChange={(e) =>
                      setSearch(e.target.value)
                    }
                    className={design.searchInput}
                  />
                </div>

                <div className={design.rightControls}>
                  {/* SORT */}
                  <div
                    className={design.dropdownWrapper}
                    ref={dropdownRef}
                  >
                    <button
                      onClick={() =>
                        setDropdownOpen(!dropdownOpen)
                      }
                      className={design.dropdownButton}
                    >
                      {
                        sortOptions.find(
                          (o) => o.value === sort
                        )?.label
                      }
                      <ChevronDown size={16} />
                    </button>

                    <AnimatePresence>
                      {dropdownOpen && (
                        <motion.div
                          initial={{
                            opacity: 0,
                            y: -6,
                          }}
                          animate={{
                            opacity: 1,
                            y: 0,
                          }}
                          exit={{ opacity: 0 }}
                          className={
                            design.dropdownMenu
                          }
                        >
                          {sortOptions.map((option) => (
                            <div
                              key={option.value}
                              onClick={() => {
                                setSort(option.value);
                                setDropdownOpen(false);
                              }}
                              className={`${design.dropdownItem} ${
                                sort === option.value
                                  ? design.dropdownActive
                                  : ""
                              }`}
                            >
                              {option.label}
                            </div>
                          ))}
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </div>

                  <button
                    onClick={() => setView("add")}
                    className={design.addButton}
                  >
                    <Plus size={16} />
                    Add Link
                  </button>
                </div>
              </div>

              {/* TABLE */}
              {processedLinks.length > 0 && (
                <div className={design.table}>
                  {processedLinks.map((link, index) => (
                    <div
                      key={link._id}
                      className={design.row}
                    >
                      <div>{index + 1}</div>
                      <div>{link.name}</div>
                      <div>
                        {link.isActive
                          ? "Active"
                          : "Inactive"}
                      </div>
                      <div className="flex justify-end gap-4">
                        <Pencil size={16} />
                        <Trash2
                          size={16}
                          className="text-red-500"
                        />
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {processedLinks.length === 0 && (
                <div className={design.emptyState}>
                  No parent links found.
                </div>
              )}
            </motion.div>
          )}

          {/* ADD VIEW */}
          {view === "add" && (
            <motion.form
              key="add"
              initial={{ opacity: 0, x: 30 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -30 }}
              transition={{ duration: 0.3 }}
              onSubmit={handleSubmit}
              className={design.form}
            >
              <input
                type="text"
                placeholder="Link Name"
                value={name}
                onChange={(e) =>
                  setName(e.target.value)
                }
                className={design.input}
                required
              />

              {/* STATUS */}
              <div
                className={design.dropdownWrapper}
                ref={statusRef}
              >
                <button
                  type="button"
                  onClick={() =>
                    setStatusDropdown(!statusDropdown)
                  }
                  className={design.dropdownButton}
                >
                  {
                    statusOptions.find(
                      (o) => o.value === isActive
                    )?.label
                  }
                  <ChevronDown size={16} />
                </button>

                <AnimatePresence>
                  {statusDropdown && (
                    <motion.div
                      initial={{
                        opacity: 0,
                        y: -6,
                      }}
                      animate={{
                        opacity: 1,
                        y: 0,
                      }}
                      exit={{ opacity: 0 }}
                      className={
                        design.dropdownMenu
                      }
                    >
                      {statusOptions.map(
                        (option) => (
                          <div
                            key={option.label}
                            onClick={() => {
                              setIsActive(
                                option.value
                              );
                              setStatusDropdown(
                                false
                              );
                            }}
                            className={`${design.dropdownItem} ${
                              isActive ===
                              option.value
                                ? design.dropdownActive
                                : ""
                            }`}
                          >
                            {option.label}
                          </div>
                        )
                      )}
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>

              <div className={design.buttonGroup}>
                <button
                  type="submit"
                  className={design.submitButton}
                >
                  Create
                </button>

                <button
                  type="button"
                  onClick={() => setView("home")}
                  className={design.cancelButton}
                >
                  Cancel
                </button>
              </div>
            </motion.form>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default LinkHome;
